INSERT INTO t_repair_project_item (
    project_id, plan_id, tenant_id, item_no, building_id, unit_name, room_id,
    location_text, work_content, quantity, unit, estimated_unit_price,
    estimated_amount, sort_order
) VALUES (
    #{projectId}, #{planId}, #{tenantId}, #{itemNo}, #{buildingId}, #{unitName}, #{roomId},
    #{locationText}, #{workContent}, #{quantity}, #{unit}, #{estimatedUnitPrice},
    #{estimatedAmount}, #{sortOrder}
)

INSERT INTO t_repair_plan_allocation_room ( plan_id, tenant_id, room_id, building_id, unit_name, owner_uid, build_area ) SELECT #{planId}, #{tenantId}, selected.room_id, selected.building_id, selected.unit_name, selected.uid, selected.build_area FROM ( SELECT DISTINCT ON (op.room_id) op.room_id, op.building_id, roster.unit_name, op.uid, op.build_area FROM c_owner_property op LEFT JOIN c_property_roster roster ON roster.tenant_id = op.tenant_id AND roster.room_id = op.room_id AND roster.status = 'ACTIVE' WHERE op.tenant_id = #{tenantId} AND op.account_status = 1 AND op.verify_status = 'VERIFIED'
AND op.building_id = #{buildingId}
AND roster.unit_name = #{unitName}
ORDER BY op.room_id, op.is_voting_delegate DESC, op.uid ) selected

INSERT INTO t_repair_project_attachment (
    project_id, tenant_id, object_key, original_file_name, content_type,
    file_size, etag, sha256, uploaded_by_account_id, uploaded_by_user_id
) VALUES (
    #{projectId}, #{tenantId}, #{objectKey}, #{originalFileName}, #{contentType},
    #{fileSize}, #{etag}, #{sha256}, #{uploadedByAccountId}, #{uploadedByUserId}
)

